1	import { describe, it, expect } from "vitest";
2	import { processScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  describe("Quote — base premiums", () => {
6	    it("returns 5G processing fee for an empty item list", () => {
7	      const result = processScenario({
8	        customer: { yearsWithMHPCO: 0 },
9	        steps: [{ op: "quote", items: [] }],
10	      });
11	      expect(result).toEqual({ results: [{ premium: 5 }] });
12	    });
13	    it.todo("computes base premium for a single sword (100G + 5G fee)");
14	    it.todo("computes base premium for each main item type (amulet, staff, potion)");
15	    it.todo("computes base premium for a single component (rune: 25G + 5G fee)");
16	    it.todo("computes base premium for 3 alike components using block discount (60G + 5G fee)");
17	    it.todo("does not apply block discount for 2 or 4 alike components");
18	    it.todo("treats different component types as not alike (2 runes + 1 moonstone = 75G)");
19	    it.todo("applies separate blocks for different component types (3 runes + 3 moonstones = 120G)");
20	  });
21	
22	  describe("Quote — item-specific modifiers", () => {
23	    it.todo("adds 50% cursed surcharge to the cursed item's base premium");
24	    it.todo("adds 30% high-enchantment surcharge for enchantment level >= 5");
25	    it.todo("applies both cursed and high-enchantment surcharges to the same item");
26	    it.todo("applies item-specific surcharges only to affected items in a multi-item policy");
27	  });
28	
29	  describe("Quote — policy-wide modifiers", () => {
30	    it.todo("adds 10% first-insurance surcharge on every quote");
31	    it.todo("applies 20% loyalty discount for customers with >= 2 years");
32	    it.todo("applies 15% follow-up discount on second and subsequent quotes");
33	    it.todo("stacks all policy-wide modifiers (loyalty + first insurance + follow-up)");
34	  });
35	
36	  describe("Quote — rounding and integration", () => {
37	    it.todo("rounds final premium up in MHPCO's favor");
38	    it.todo("newcomer with cursed sword: premium is 165G");
39	    it.todo("long-standing customer second contract with cursed high-enchantment sword: premium is 160G");
40	  });
41	
42	  describe("Quote — errors", () => {
43	    it.todo("rejects unknown item type with an error");
44	  });
45	
46	  describe("Claim — standard reimbursement", () => {
47	    it.todo("pays full damage minus 100G deductible for a standard item");
48	    it.todo("applies deductible per damage entry when multiple items are damaged");
49	  });
50	
51	  describe("Claim — special clauses", () => {
52	    it.todo("reimburses at 50% for items with enchantment >= 8, then deductible");
53	    it.todo("fully reimburses dragon-material items, then deductible");
54	    it.todo("applies 50% rule when item has both dragon material and enchantment >= 8");
55	  });
56	
57	  describe("Claim — cap and exhaustion", () => {
58	    it.todo("caps total payout at 2x the insurance sum");
59	    it.todo("tracks remaining cap across multiple claims on the same policy");
60	  });
61	
62	  describe("Claim — rounding", () => {
63	    it.todo("rounds payout down in MHPCO's favor");
64	  });
65	
66	  describe("Claim — errors", () => {
67	    it.todo("rejects damage to an item not covered by the policy");
68	    it.todo("rejects more damage entries of a type than items insured");
69	    it.todo("rejects negative damage amounts");
70	  });
71	});
